use localcode_core::llm::provider::ChatMessage;
use serde::{Deserialize, Serialize};
use std::path::PathBuf;

#[derive(Debug, Clone, Serialize, Deserialize)]

[pub fn new(project_path: &str) -> Self]
impl Conversation {
    pub fn new(project_path: &str) -> Self {
        Self {
            id: uuid::Uuid::new_v4().to_string(),
            messages: Vec::new(),
            created_at: chrono::Utc::now().to_rfc3339(),
            project_path: project_path.to_string(),
        }
    }

    pub fn add_message(&mut self, role: &str, content: &str) {
        self.messages.push(ChatMessage {
            role: role.to_string(),
            content: content.to_string(),
            tool_calls: None,
            tool_call_id: None,
        });
    }

    pub fn save(&self) -> Result<(), Box<dyn std::error::Error>> {
        let dir = history_dir();
        std::fs::create_dir_all(&dir)?;
        let path = dir.join(format!("{}.json", self.id));
        let content = serde_json::to_string_pretty(self)?;
        std::fs::write(path, content)?;
        Ok(())
    }
}

[pub fn parse_slash(input: &str) -> Option<SlashCommand>]
pub fn parse_slash(input: &str) -> Option<SlashCommand> {
    let trimmed = input.trim();
    if !trimmed.starts_with('/') {
        return None;
    }

    let parts: Vec<&str> = trimmed.splitn(2, ' ').collect();
    let cmd = parts[0];
    let arg = parts.get(1).map(|s| s.to_string());

    Some(match cmd {
        "/help" | "/h" => SlashCommand::Help,
        "/clear" | "/c" => SlashCommand::Clear,
        "/model" | "/m" => SlashCommand::Model(arg),
        "/memory" => SlashCommand::Memory,
        "/commit" => SlashCommand::Commit,
        "/config" => SlashCommand::Config,
        "/exit" | "/quit" | "/q" => SlashCommand::Exit,
        _ => SlashCommand::Unknown(cmd.to_string()),
    })
}

[pub fn print_help()]
pub fn print_help() {
    println!("  Slash Commands:");
    println!("    /help          Show this help");
    println!("    /clear         Clear conversation");
    println!("    /model [name]  Switch model/provider");
    println!("    /memory        Show memory for this project");
    println!("    /commit        AI-generated commit message");
    println!("    /config        Show configuration");
    println!("    /exit          Exit REPL");
    println!();
}

[pub fn print_header()]
pub fn print_header() {
    let version = env!("CARGO_PKG_VERSION");
    println!();
    println!("  {}", "╭─────────────────────────────────╮".dark_grey());
    println!("  {}  LocalCode v{}               {}",
        "│".dark_grey(), version, "│".dark_grey());
    print_project_info();
    println!("  {}", "╰─────────────────────────────────╯".dark_grey());
    println!();
}

[fn print_project_info()]
fn print_project_info() {
    let cwd = std::env::current_dir()
        .map(|p| p.display().to_string())
        .unwrap_or_else(|_| "unknown".to_string());

    let project_name = std::path::Path::new(&cwd)
        .file_name()
        .and_then(|n| n.to_str())
        .unwrap_or("unknown");

    println!("  {}  Project: {:<22} {}",
        "│".dark_grey(), project_name, "│".dark_grey());
}

[pub fn print_prompt()]
pub fn print_prompt() {
    print!("{} ", ">".green().bold());
    io::stdout().flush().unwrap();
}

[pub fn print_assistant_prefix()]
pub fn print_assistant_prefix() {
    println!();
}

[pub fn print_tool_call(name: &str, args: &serde_json::Value)]
pub fn print_tool_call(name: &str, args: &serde_json::Value) {
    let args_str = if let Some(obj) = args.as_object() {
        obj.iter()
            .map(|(k, v)| {
                let val = match v {
                    serde_json::Value::String(s) => {
                        if s.len() > 60 {
                            format!("{}...", &s[..57])
                        } else {
                            s.clone()
                        }
                    }
                    _ => v.to_string(),
                };
                format!("{}={}", k, val)
            })
            .collect::<Vec<_>>()
            .join(", ")
    } else {
        String::new()
    };

    println!("  {} {} {}", "[".dark_grey(), name.cyan(), "]".dark_grey());
}

[pub fn print_tool_result(name: &str, result: &str)]
pub fn print_tool_result(name: &str, result: &str) {
    let truncated = if result.len() > 200 {
        format!("{}...", &result[..197])
    } else {
        result.to_string()
    };
    println!("  {} {}", "✓".green(), truncated.dark_grey());
}

[pub fn print_error(msg: &str)]
pub fn print_error(msg: &str) {
    eprintln!("  {} {}", "✗".red(), msg);
}

[pub fn print_success(msg: &str)]
pub fn print_success(msg: &str) {
    println!("  {} {}", "✓".green(), msg);
}

[pub fn print_info(msg: &str)]
pub fn print_info(msg: &str) {
    println!("  {} {}", "ℹ".blue(), msg);
}

[pub fn print_markdown(text: &str)]
pub fn print_markdown(text: &str) {
    // Simple markdown rendering — print as-is with basic formatting
    for line in text.lines() {
        if line.starts_with("```") {
            println!("{}", line.dark_grey());
        } else if line.starts_with("# ") {
            println!("{}", line[2..].bold());
        } else if line.starts_with("## ") {
            println!("{}", line[3..].bold());
        } else if line.starts_with("- ") || line.starts_with("* ") {
            println!("  {} {}", "•".dark_grey(), &line[2..]);
        } else {
            println!("{}", line);
        }
    }
}

use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::path::PathBuf;
use std::process::Command;

#[derive(Debug, Clone, Serialize, Deserialize)]

[pub struct HookConfig]
pub struct HookConfig {
    pub command: String,
    #[serde(default = "default_on_failure")]
    pub on_failure: String,
}

[fn default_on_failure() -> String]
fn default_on_failure() -> String {
    "warn".to_string()
}

[pub fn load() -> Self]
impl HooksConfig {
    pub fn load() -> Self {
        let path = hooks_path();
        if path.exists() {
            if let Ok(content) = std::fs::read_to_string(&path) {
                if let Ok(config) = toml::from_str(&content) {
                    return config;
                }
            }
        }
        Self::default()
    }

    pub fn run_hook(&self, hook_name: &str, context: &HashMap<String, String>) -> bool {
        let hook = match hook_name {
            "post_edit" => &self.post_edit,
            "pre_commit" => &self.pre_commit,
            "post_commit" => &self.post_commit,
            _ => return true,
        };

        if let Some(hook) = hook {
            let mut cmd = hook.command.clone();
            for (key, value) in context {
                cmd = cmd.replace(&format!("{{{}}}", key), value);
            }

            let output = Command::new("sh")
                .arg("-c")
                .arg(&cmd)
                .output();

            match output {
                Ok(out) if out.status.success() => true,
                Ok(_) if hook.on_failure == "block" => {
                    eprintln!("Hook '{}' failed and blocked the action", hook_name);
                    false
                }
                Ok(_) => {
                    eprintln!("Hook '{}' failed (warning)", hook_name);
                    true
                }
                Err(e) => {
                    eprintln!("Hook '{}' error: {}", hook_name, e);
                    hook.on_failure != "block"
                }
            }
        } else {
            true
        }
    }
}

use futures::StreamExt;
use std::io::{self, Write};
