/// Collect a ChatStream into a complete text string

) -> Result<String, CoreError> {
    let mut text = String::new();

    while let Some(chunk) = stream.next().await {
        match chunk? {
            ChatChunk::Text(t) => text.push_str(&t),
            ChatChunk::Done => break,
            ChatChunk::Error(e) => return Err(CoreError::Llm(e)),
            _ => {}
        }
    }

    Ok(text)
}

/// Collect a ChatStream into a ChatMessage with potential tool calls

) -> Result<ChatMessage, CoreError> {
    let mut text = String::new();
    let mut tool_calls: Vec<ToolCall> = Vec::new();
    let mut current_tool: Option<(String, String, String)> = None; // (id, name, args)

    while let Some(chunk) = stream.next().await {
        match chunk? {
            ChatChunk::Text(t) => text.push_str(&t),
            ChatChunk::ToolCallStart { id, name } => {
                current_tool = Some((id, name, String::new()));
            }
            ChatChunk::ToolCallDelta { arguments_delta, .. } => {
                if let Some((_, _, ref mut args)) = current_tool {
                    args.push_str(&arguments_delta);
                }
            }
            ChatChunk::ToolCallEnd { .. } => {
                if let Some((id, name, args)) = current_tool.take() {
                    tool_calls.push(ToolCall {
                        id,
                        call_type: "function".to_string(),
                        function: ToolCallFunction {
                            name,
                            arguments: args,
                        },
                    });
                }
            }
            ChatChunk::Done => break,
            ChatChunk::Error(e) => return Err(CoreError::Llm(e)),
        }
    }

    Ok(ChatMessage {
        role: "assistant".to_string(),
        content: text,
        tool_calls: if tool_calls.is_empty() {
            None
        } else {
            Some(tool_calls)
        },
        tool_call_id: None,
    })
}

use async_trait::async_trait;
use futures::StreamExt;
use reqwest::Client;
use tokio_stream::wrappers::ReceiverStream;

use super::provider::*;
use crate::CoreError;

[pub struct AnthropicProvider]
pub struct AnthropicProvider {
    api_key: String,
    model: String,
    client: Client,
}

[pub fn new(api_key: &str, model: &str) -> Self]
impl AnthropicProvider {
    pub fn new(api_key: &str, model: &str) -> Self {
        Self {
            api_key: api_key.to_string(),
            model: model.to_string(),
            client: Client::new(),
        }
    }
}

[fn name(&self) -> &str]
impl LLMProvider for AnthropicProvider {
    fn name(&self) -> &str {
        "anthropic"
    }

    async fn chat(
        &self,
        messages: Vec<ChatMessage>,
        opts: ChatOptions,
    ) -> Result<ChatStream, CoreError> {
        let api_messages: Vec<serde_json::Value> = messages
            .iter()
            .filter(|m| m.role != "system")
            .map(|msg| {
                if msg.role == "tool" {
                    serde_json::json!({
                        "role": "user",
                        "content": [{
                            "type": "tool_result",
                            "tool_use_id": msg.tool_call_id.as_deref().unwrap_or(""),
                            "content": msg.content
                        }]
                    })
                } else {
                    serde_json::json!({
                        "role": msg.role,
                        "content": msg.content
                    })
                }
            })
            .collect();

        let mut body = serde_json::json!({
            "model": self.model,
            "messages": api_messages,
            "max_tokens": opts.max_tokens,
            "temperature": opts.temperature,
            "stream": true,
        });

        if let Some(ref system) = opts.system {
            body["system"] = serde_json::json!(system);
        }

        if !opts.tools.is_empty() {
            let anthropic_tools: Vec<serde_json::Value> = opts
                .tools
                .iter()
                .map(|t| {
                    serde_json::json!({
                        "name": t.function.name,
                        "description": t.function.description,
                        "input_schema": t.function.parameters,
                    })
                })
                .collect();
            body["tools"] = serde_json::json!(anthropic_tools);
        }

        let response = self
            .client
            .post("https://api.anthropic.com/v1/messages")
            .header("x-api-key", &self.api_key)
            .header("anthropic-version", "2023-06-01")
            .header("Content-Type", "application/json")
            .json(&body)
            .send()
            .await?;

        if !response.status().is_success() {
            let status = response.status();
            let body = response.text().await.unwrap_or_default();
            return Err(CoreError::Llm(format!(
                "Anthropic API error {}: {}",
                status, body
            )));
        }

        let (tx, rx) = tokio::sync::mpsc::channel(100);
        let mut stream = response.bytes_stream();

tokio::spawn(async move {
    let mut buffer = String::new();
    let mut current_tool_id = String::new();

    while let Some(chunk) = stream.next().await {
        match chunk {
            Ok(bytes) => {
                let text = String::from_utf8_lossy(&bytes);
                buffer.push_str(&text);

                while let Some(pos) = buffer.find('\n') {
                    let line = buffer[..pos].to_string();
                    buffer = buffer[pos + 1..].to_string();

                    let line = line.trim();
                    if !line.starts_with("data: ") {
                        continue;
                    }
                    let data = &line[6..];

                    if let Ok(parsed) = serde_json::from_str::<serde_json::Value>(data) {
                        let event_type = parsed["type"].as_str().unwrap_or("");

                        match event_type {
                            "content_block_start" => {
                                let block = &parsed["content_block"];
                                if block["type"] == "tool_use" {
                                    let id =
                                        block["id"].as_str().unwrap_or("").to_string();
                                    let name =
                                        block["name"].as_str().unwrap_or("").to_string();
                                    current_tool_id = id.clone();
                                    let _ = tx
                                        .send(Ok(ChatChunk::ToolCallStart {
                                            id,
                                            name,
                                        }))
                                        .await;
                                }
                            }
                            "content_block_delta" => {
                                let delta = &parsed["delta"];
                                if delta["type"] == "text_delta" {
                                    if let Some(text) = delta["text"].as_str() {
                                        let _ = tx
                                            .send(Ok(ChatChunk::Text(text.to_string())))
                                            .await;
                                    }
                                } else if delta["type"] == "input_json_delta" {
                                    if let Some(json) = delta["partial_json"].as_str() {
                                        let _ = tx
                                            .send(Ok(ChatChunk::ToolCallDelta {
                                                id: current_tool_id.clone(),
                                                arguments_delta: json.to_string(),
                                            }))
                                            .await;
                                    }
                                }
                            }
                            "content_block_stop" => {
                                if !current_tool_id.is_empty() {
                                    let _ = tx
                                        .send(Ok(ChatChunk::ToolCallEnd {
                                            id: current_tool_id.clone(),
                                        }))
                                        .await;
                                    current_tool_id.clear();
                                }
                            }
                            "message_stop" => {
                                let _ = tx.send(Ok(ChatChunk::Done)).await;
                                return;
                            }
                            _ => {}
                        }
                    }
                }
            }
            Err(e) => {
                let _ = tx.send(Err(CoreError::Http(e))).await;
                return;

                }
            }
        }

        let _ = tx.send(Ok(ChatChunk::Done)).await;
    });

    Ok(Box::pin(ReceiverStream::new(rx)))
}

    messages: Vec<ChatMessage>,
