#[derive(Debug, Clone, Serialize, Deserialize)]

#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum ChunkKind {
    Function,
    Class,
    Module,
    Block,
}

/// Extract function/method signature from a chunk for search enrichment

[pub fn extract_signature(chunk: &CodeChunk) -> Option<String>]
pub fn extract_signature(chunk: &CodeChunk) -> Option<String> {
    for line in chunk.content.lines() {
        let trimmed = line.trim();
        // Rust
        if trimmed.starts_with("fn ")
            || trimmed.starts_with("pub fn ")
            || trimmed.starts_with("async fn ")
            || trimmed.starts_with("pub async fn ")
        {
            // Extract up to opening brace or end of line
            let sig = trimmed.split('{').next().unwrap_or(trimmed).trim();
            return Some(sig.to_string());
        }
        // Python
        if trimmed.starts_with("def ") || trimmed.starts_with("async def ") {
            let sig = trimmed.split(':').next().unwrap_or(trimmed).trim();
            return Some(sig.to_string());
        }
        // JS/TS
        if trimmed.starts_with("function ")
            || trimmed.starts_with("export function ")
            || trimmed.starts_with("async function ")
            || trimmed.starts_with("export async function ")
        {
            let sig = trimmed.split('{').next().unwrap_or(trimmed).trim();
            return Some(sig.to_string());
        }
        // Go
        if trimmed.starts_with("func ") {
            let sig = trimmed.split('{').next().unwrap_or(trimmed).trim();
            return Some(sig.to_string());
        }
        // Class
        if trimmed.starts_with("class ") || trimmed.starts_with("pub struct ") || trimmed.starts_with("struct ") {
            let sig = trimmed.split('{').next().unwrap_or(trimmed).trim();
            return Some(sig.to_string());
        }
    }
    None
}

/// Enrich chunk content by prepending its signature for better search indexing
pub fn enrich_chunk(chunk: &mut CodeChunk) {
    if let Some(sig) = extract_signature(chunk) {
        // Prepend signature as a search-friendly header
        chunk.content = format!("[{}]\n{}", sig, chunk.content);
    }
}

/// Split file into meaningful code chunks (function-level)
pub fn chunk_file(file_path: &str, max_chunk_lines: usize) -> CoreResult<Vec<CodeChunk>> {
    let content = std::fs::read_to_string(file_path)?;
    let lines: Vec<&str> = content.lines().collect();

    if lines.is_empty() {
        return Ok(Vec::new());
    }

    let mut chunks = Vec::new();
    let mut current_start = 0;
    let mut brace_depth = 0;
    let mut in_function = false;

    for (i, line) in lines.iter().enumerate() {
        let trimmed = line.trim();

        // Detect function/class starts
        let is_def = trimmed.starts_with("fn ")
            || trimmed.starts_with("pub fn ")
            || trimmed.starts_with("async fn ")
            || trimmed.starts_with("pub async fn ")
            || trimmed.starts_with("def ")
            || trimmed.starts_with("async def ")
            || trimmed.starts_with("class ")
            || trimmed.starts_with("function ")
            || trimmed.starts_with("export function ")
            || trimmed.starts_with("export async function ")
            || trimmed.starts_with("async function ")
            || trimmed.starts_with("func ")
            || trimmed.starts_with("pub struct ")
            || trimmed.starts_with("impl ");

    if is_def && !in_function {
        // Save previous block if non-empty
        if i > current_start {
            let block: String = lines[current_start..i].join("\n");
            if !block.trim().is_empty() {
                let mut chunk = CodeChunk {
                    file: file_path.to_string(),
                    start_line: current_start + 1,
                    end_line: i,
                    content: block,
                    kind: ChunkKind::Block,
                };
                enrich_chunk(&mut chunk);
                chunks.push(chunk);
            }
        }
        current_start = i;
        in_function = true;
        brace_depth = 0;
    }

    // Track braces
    for ch in trimmed.chars() {
        if ch == '{' {
            brace_depth += 1;
        } else if ch == '}' {
            brace_depth -= 1;
        }
    }

    // Python: detect dedent (simplified)
    let is_python = file_path.ends_with(".py");

    // End of function (brace-based languages)
    if in_function && !is_python && brace_depth <= 0 && i > current_start {
        let block: String = lines[current_start..=i].join("\n");
        let mut chunk = CodeChunk {
            file: file_path.to_string(),
            start_line: current_start + 1,
            end_line: i + 1,
            content: block,
            kind: ChunkKind::Function,
        };
        enrich_chunk(&mut chunk);
        chunks.push(chunk);
        current_start = i + 1;
        in_function = false;
    }

    // Max chunk size fallback
    if i - current_start >= max_chunk_lines {
        let block: String = lines[current_start..=i].join("\n");
        let mut chunk = CodeChunk {
            file: file_path.to_string(),
            start_line: current_start + 1,
            end_line: i + 1,
            content: block,
            kind: if in_function {
                ChunkKind::Function
            } else {
                ChunkKind::Block
            },
        };
        enrich_chunk(&mut chunk);
        chunks.push(chunk);
        current_start = i + 1;
        in_function = false;
        brace_depth = 0;
    }
}

// Remaining
if current_start < lines.len() {
    let block: String = lines[current_start..].join("\n");
    if !block.trim().is_empty() {
        let mut chunk = CodeChunk {
            file: file_path.to_string(),
            start_line: current_start + 1,
            end_line: lines.len(),
            content: block,

                kind: ChunkKind::Block,
            };
            enrich_chunk(&mut chunk);
            chunks.push(chunk);
        }
    }

    Ok(chunks)
}

use ignore::WalkBuilder;

use super::chunker;
use super::store::CodeIndex;
use crate::CoreResult;

const CODE_EXTENSIONS: &[&str] = &[
    "rs", "py", "ts", "tsx", "js", "jsx", "go", "java", "c", "cpp", "h", "hpp",
    "rb", "php", "swift", "kt", "scala", "cs", "vue", "svelte", "lua", "sh",
    "bash", "zsh", "sql", "toml", "yaml", "yml", "json", "md", "txt",
];

/// Build or update the index for a project

[pub fn build_index(project_path: &str) -> CoreResult<CodeIndex>]
pub fn build_index(project_path: &str) -> CoreResult<CodeIndex> {
    let index_path = CodeIndex::index_path(project_path);
    let mut index = CodeIndex::load(&index_path).unwrap_or_default();

    let walker = WalkBuilder::new(project_path)
        .hidden(true)
        .git_ignore(true)
        .build();

    let mut changed = false;

    for entry in walker {
        let entry = entry.map_err(|e| crate::CoreError::Other(e.to_string()))?;
        let path = entry.path();

        if !path.is_file() {
            continue;
        }

        let ext = path
            .extension()
            .and_then(|e| e.to_str())
            .unwrap_or("");

        if !CODE_EXTENSIONS.contains(&ext) {
            continue;
        }

        let path_str = path.to_string_lossy().to_string();

        // Check if file changed
        let metadata = std::fs::metadata(path)?;
        let modified = metadata
            .modified()
            .ok()
            .and_then(|t| t.duration_since(std::time::UNIX_EPOCH).ok())
            .map(|d| d.as_secs())
            .unwrap_or(0);

        if let Some(&cached_hash) = index.file_hashes.get(&path_str) {
            if cached_hash == modified {
                continue; // File hasn't changed
            }
        }

        // Re-index file
        index.remove_file(&path_str);

        if let Ok(chunks) = chunker::chunk_file(&path_str, 80) {
            for chunk in &chunks {
                index.add_chunk(chunk);
            }
        }

        index.file_hashes.insert(path_str, modified);
        changed = true;
    }

    // Recompute BM25 stats if anything changed
    if changed {
        index.compute_stats();
    }

    index.save(&index_path)?;
    Ok(index)
}

[pub fn index_if_needed(project_path: &str, max_age_secs: u64) -> CoreResult<CodeIndex>]
pub fn index_if_needed(project_path: &str, max_age_secs: u64) -> CoreResult<CodeIndex> {
    let index_path = CodeIndex::index_path(project_path);

    if !index_path.exists() {
        return build_index(project_path);
    }

    let metadata = std::fs::metadata(&index_path)?;
    let modified = metadata
        .modified()
        .ok()
        .and_then(|t| t.duration_since(std::time::UNIX_EPOCH).ok())
        .map(|d| d.as_secs())
        .unwrap_or(0);
    let now = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default()
        .as_secs();

    if now - modified > max_age_secs {
        build_index(project_path)
    } else {
        CodeIndex::load(&index_path)
    }
}

[pub fn ensure_index_fresh(project_path: &str, max_age_secs: u64) -> CoreResult<CodeIndex>]
pub fn ensure_index_fresh(project_path: &str, max_age_secs: u64) -> CoreResult<CodeIndex> {
    index_if_needed(project_path, max_age_secs)
}

    query: &str,
    top_k: usize,
) -> CoreResult<Vec<String>> {
    let index_path = CodeIndex::index_path(project_path);
    let index = CodeIndex::load(&index_path)?;

    if index.entries.is_empty() {
        return Err(crate::CoreError::Other(
