    let repo = git2::Repository::discover(path)?;
    let branches = repo.branches(Some(git2::BranchType::Local))?;

    let mut names = Vec::new();
    for branch in branches {
        let (branch, _) = branch?;
        if let Some(name) = branch.name()? {
            names.push(name.to_string());
        }
    }
    Ok(names)
