export default function MentionPopup({
  visible,
  filter,
  position,
  onSelect,
  onClose,
}: MentionPopupProps) {
  const [selectedIndex, setSelectedIndex] = useState(0);
  const containerRef = useRef<HTMLDivElement>(null);
  const optionRefs = useRef<(HTMLDivElement | null)[]>([]);

  // Filter options based on input
  const filteredOptions = MENTION_OPTIONS.filter((opt) => {
    if (!filter) return true;
    const lowerFilter = filter.toLowerCase();
    return (
      opt.label.toLowerCase().includes(lowerFilter) ||
      opt.prefix.toLowerCase().includes(lowerFilter) ||
      opt.description.toLowerCase().includes(lowerFilter)
    );
  });

  // Reset selection when filter changes
  useEffect(() => {
    setSelectedIndex(0);
  }, [filter]);

  // Scroll selected into view
  useEffect(() => {
    optionRefs.current[selectedIndex]?.scrollIntoView({ block: 'nearest' });
  }, [selectedIndex]);

  // Keyboard navigation
  useEffect(() => {
    if (!visible) return;

    const handleKeyDown = (e: KeyboardEvent) => {
      switch (e.key) {
        case 'ArrowDown':
          e.preventDefault();
          e.stopPropagation();
          setSelectedIndex((prev) => Math.min(prev + 1, filteredOptions.length - 1));
          break;
        case 'ArrowUp':
          e.preventDefault();
          e.stopPropagation();
          setSelectedIndex((prev) => Math.max(prev - 1, 0));
          break;
        case 'Enter':
        case 'Tab':
          e.preventDefault();
          e.stopPropagation();
          if (filteredOptions[selectedIndex]) {
            onSelect(filteredOptions[selectedIndex]);
          }
          break;
        case 'Escape':
          e.preventDefault();
          onClose();
          break;
      }
    };

    window.addEventListener('keydown', handleKeyDown, true);
    return () => window.removeEventListener('keydown', handleKeyDown, true);
  }, [visible, selectedIndex, filteredOptions, onSelect, onClose]);

  // Close on outside click
  useEffect(() => {
    if (!visible) return;

    const handleClick = (e: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(e.target as Node)) {
        onClose();
      }
    };

    document.addEventListener('mousedown', handleClick);
    return () => document.removeEventListener('mousedown', handleClick);
  }, [visible, onClose]);

  if (!visible) return null;

  return (
    <div
      ref={containerRef}
      style={{
        ...styles.container,
        top: position.top,
        left: position.left,
      }}
    >
      <div style={styles.header}>Mentions</div>
      {filteredOptions.length === 0 ? (
        <div style={styles.empty}>No matches found</div>
      ) : (
        filteredOptions.map((option, index) => (
          <div
            key={option.id}
            ref={(el) => { optionRefs.current[index] = el; }}
            style={{
              ...styles.option,
              ...(index === selectedIndex ? styles.optionActive : {}),
            }}
            onClick={() => onSelect(option)}
            onMouseEnter={() => setSelectedIndex(index)}
          >
            <div style={{ ...styles.optionIcon, background: getIconBg(option.id) }}>
              {option.icon}
            </div>
            <div style={styles.optionText}>
              <span style={styles.optionLabel}>{option.label}</span>
              <span style={styles.optionDesc}>{option.description}</span>
            </div>
            <span style={styles.optionPrefix}>{option.prefix}</span>
          </div>
        ))
      )}
    </div>
  );
}

import { useState, useRef, useEffect, useCallback } from 'react';
