[pub fn new(provider: Arc<dyn LLMProvider>, registry: ToolRegistry) -> Self]
impl AgentEngine {
    pub fn new(provider: Arc<dyn LLMProvider>, registry: ToolRegistry) -> Self {
        Self {
            provider,
            registry,
            max_iterations: 30,
            system_prompt: String::new(),
            context_manager: None,
            memory_manager: None,
            session_state: None,
        }
    }

    pub fn with_max_iterations(mut self, max: usize) -> Self {
        self.max_iterations = max;
        self
    }

    pub fn with_system_prompt(mut self, prompt: String) -> Self {
        self.system_prompt = prompt;
        self
    }

    /// Initialize memory, auto-discovery, and session for a project
    pub fn initialize(&mut self, project_path: &str) {
        // Set up memory manager with auto-discovery
        let mut memory = MemoryManager::new();

        // Auto-discover project if stale (> 1 hour)
        if memory.needs_reindex(project_path, 3600) {
            memory.auto_discover_project(project_path);
            let _ = memory.save();
        }

        // Build enriched system prompt from memory
        let memory_ctx = memory.build_context(project_path);
        if !memory_ctx.is_empty() {
            if self.system_prompt.is_empty() {
                self.system_prompt = format!(
                    "You are LocalCode Agent, an autonomous AI coding assistant.\n\n{}",
                    memory_ctx
                );
            } else {
                self.system_prompt.push_str("\n\n");
                self.system_prompt.push_str(&memory_ctx);
            }
        }

        // Set up context manager
        let ctx_manager = ContextManager::new(self.max_iterations * 4096)
            .with_provider(self.provider.clone());
        self.context_manager = Some(ctx_manager);

        // Load or create session state
        let session = SessionState::load(project_path)
            .ok()
            .flatten()
            .unwrap_or_else(|| SessionState::new(project_path));
        self.session_state = Some(session);

        self.memory_manager = Some(memory);
    }

    fn build_system_prompt(&self, ctx: &ToolContext) -> String {
        let tools_desc: Vec<String> = self
            .registry
            .list()
            .iter()
            .enumerate()
            .map(|(i, name)| {
                let tool = self.registry.get(name).unwrap();
                format!("{}. {} - {}", i + 1, name, tool.description())
            })
            .collect();

        let memory_context = if self.system_prompt.is_empty() {
            String::new()
        } else {
            self.system_prompt.clone()
        };

[fn track_file_modification(&mut self, tool_name: &str, args: &serde_json::Value)]
    fn track_file_modification(&mut self, tool_name: &str, args: &serde_json::Value) {
        if let Some(ref mut session) = self.session_state {
            match tool_name {
                "write_file" | "edit_file" | "create_file" | "delete_file" => {
                    if let Some(path) = args.get("path").and_then(|p| p.as_str()) {
                        session.add_file_modified(path);
                    }
                }
                _ => {}
            }
        }
    }

[fn finalize_session(&mut self, task: &str, final_response: &str)]
    fn finalize_session(&mut self, task: &str, final_response: &str) {
        if let (Some(ref mut memory), Some(ref session)) =
            (&mut self.memory_manager, &self.session_state)
        {
            let summary = super::memory::SessionSummary {
                timestamp: std::time::SystemTime::now()
                    .duration_since(std::time::UNIX_EPOCH)
                    .unwrap_or_default()
                    .as_secs(),
                task: task.to_string(),
                files_modified: session.files_modified.clone(),
                tasks_completed: session.tasks_completed.clone(),
                summary: final_response.chars().take(500).collect(),
            };

            memory.save_session_summary(&session.project_path, summary);
            let _ = memory.save();
        }

        if let Some(ref session) = self.session_state {
            let _ = session.save();
        }
    }

    task: &str,
    ctx: &ToolContext,
    on_event: &(dyn Fn(AgentEvent) + Send + Sync),
) -> Result<String, CoreError> {
    let system = self.build_system_prompt(ctx);
    let tool_defs = self.registry.tool_definitions();

    let mut messages = vec![ChatMessage {
        role: "user".to_string(),
        content: task.to_string(),
        tool_calls: None,
        tool_call_id: None,
    }];

    // Add to context manager if available
    if let Some(ref mut cm) = self.context_manager {
        cm.add_message(ChatMessage {
            role: "system".to_string(),
            content: system.clone(),
            tool_calls: None,
            tool_call_id: None,
        });
        cm.add_message(messages[0].clone());
    }

    for _iteration in 0..self.max_iterations {
        let opts = ChatOptions {
            temperature: 0.3,
            max_tokens: 4096,
            tools: tool_defs.clone(),
            stream: false,
            system: Some(system.clone()),
            stop: None,
        };

        // Use chat_sync for reliable tool call parsing (streaming tool calls are fragile)
        let mut response = self.provider.chat_sync(messages.clone(), opts).await?;

        // Fallback: parse tool calls from content if model outputs them as JSON text
        // (common with Ollama/local models that don't use structured tool_calls)
        if response.tool_calls.is_none() && !response.content.is_empty() {
            if let Some(parsed) = parse_tool_call_from_content(&response.content, &self.registry) {
                response.tool_calls = Some(vec![parsed]);
                response.content = String::new();
            }
        }

        // Check for tool calls
        if let Some(ref tool_calls) = response.tool_calls {
            // Emit the text portion if any
            if !response.content.is_empty() {
                on_event(AgentEvent::TextChunk(response.content.clone()));
            }

            messages.push(response.clone());
            if let Some(ref mut cm) = self.context_manager {
                cm.add_message(response.clone());
            }

            for tc in tool_calls {
                let args: serde_json::Value =
                    serde_json::from_str(&tc.function.arguments).unwrap_or_default();

                on_event(AgentEvent::Step(AgentStep {
                    step_type: "tool_call".to_string(),
                    tool: Some(tc.function.name.clone()),
                    args: Some(args.clone()),
                    result: None,
                    content: None,
                    timestamp: now_ms(),
                }));

                // Track file modifications
                self.track_file_modification(&tc.function.name, &args);

                let result = self
                    .registry
                    .execute(&tc.function.name, args, ctx)
                    .await
                    .unwrap_or_else(|e| format!("Error: {}", e));

                on_event(AgentEvent::Step(AgentStep {
                    step_type: "tool_result".to_string(),
                    tool: Some(tc.function.name.clone()),
                    args: None,
                    result: Some(result.clone()),
                    content: None,
                    timestamp: now_ms(),
                }));

                let tool_msg = ChatMessage {
                    role: "tool".to_string(),
                    content: result,
                    tool_calls: None,
                    tool_call_id: Some(tc.id.clone()),
                };
                messages.push(tool_msg.clone());
                if let Some(ref mut cm) = self.context_manager {
                    cm.add_message(tool_msg);
                }
            }

            // Check if context compression is needed
            if let Some(ref mut cm) = self.context_manager {
                if cm.needs_compression() {
                    cm.compress().await;
                    // Use compressed messages for next iteration
                    messages = cm.messages().to_vec();
                    // Remove system message from messages list (it's passed via opts)
                    if !messages.is_empty() && messages[0].role == "system" {
                        messages.remove(0);
                    }
                    // Also remove any summary system messages
                    messages.retain(|m| !(m.role == "system" && m.content.starts_with("[Previous")));
                }
            }
        } else {
            // No tool calls — final response
            on_event(AgentEvent::Done(response.content.clone()));
            self.finalize_session(task, &response.content);
            return Ok(response.content);
        }
    }

    let msg = "[Agent reached max iterations]".to_string();
    on_event(AgentEvent::Done(msg.clone()));
    self.finalize_session(task, &msg);
    Ok(msg)
}

/// Execute agent with XML tool calling (for local models without native tool calling)

        task: &str,
        ctx: &ToolContext,
        on_event: &(dyn Fn(AgentEvent) + Send + Sync),
    ) -> Result<String, CoreError> {
        let tools_desc: Vec<String> = self
            .registry
            .list()
            .iter()
            .enumerate()
            .map(|(i, name)| {
                let tool = self.registry.get(name).unwrap();
                format!("{}. {}({}) - {}", i + 1, name, "", tool.description())
            })
            .collect();

        let system = format!(
            r#"You are LocalCode Agent, an AI coding assistant that MUST use tools to complete tasks.
You CANNOT answer questions directly — you MUST use the tools below to take action.
You have full access to the user's filesystem and can run any command.

IMPORTANT: You MUST respond with a tool call in EVERY response. Never respond with plain text unless you are done with the task.

## How to call a tool
Respond with EXACTLY this XML format (nothing else):
<tool>tool_name</tool>
<args>{{"param": "value"}}</args>

## Example
User: "list files in src/"
Your response:
<tool>list_dir</tool>
<args>{{"path": "src"}}</args>

User: "read screenshot on Desktop"
Your response:
<tool>list_dir</tool>
<args>{{"path": "Desktop"}}</args>

User: "run the tests"
Your response:
<tool>run_command</tool>
<args>{{"command": "cargo test"}}</args>

## Available Tools
{tools}

## Project Directory: {project}

## Rules
- ALWAYS start by using a tool. Never just explain what you would do.
- Use run_command to execute shell commands (python, pip, npm, cargo, etc.)
- Use list_dir and read_file to explore files before modifying them.
- Use write_file to create scripts and run_command to execute them.
- If a task requires generating code to solve a problem (e.g. OCR, image processing, data parsing), write the code to a temp file with write_file, then run it with run_command. If one approach fails, try a different library or method.
- Only call ONE tool at a time. Wait for the result before calling the next.
- When you are completely done, respond with a plain text summary (no tool call)."#,
            tools = tools_desc.join("\n"),
            project = ctx.project_path
        );

        let mut conversation = vec![ChatMessage {
            role: "user".to_string(),
            content: task.to_string(),
            tool_calls: None,
            tool_call_id: None,
        }];

        for _iteration in 0..self.max_iterations {
            let opts = ChatOptions {
                temperature: 0.3,
                max_tokens: 2048,
                stream: false,
                system: Some(system.clone()),
                ..Default::default()
            };

            let response = self.provider.chat_sync(conversation.clone(), opts).await?;

            if let Some((tool_name, args_str)) = parse_xml_tool_call(&response.content) {
                let args: serde_json::Value =
                    serde_json::from_str(&args_str).unwrap_or_default();

            on_event(AgentEvent::Step(AgentStep {
                step_type: "tool_call".to_string(),
                tool: Some(tool_name.clone()),
                args: Some(args.clone()),
                result: None,
                content: None,
                timestamp: now_ms(),
            }));

            if tool_name == "done" {
                let summary = args["summary"]
                    .as_str()
                    .unwrap_or("Task completed")
                    .to_string();
                on_event(AgentEvent::Done(summary.clone()));
                self.finalize_session(task, &summary);
                return Ok(summary);
            }

            // Track file modifications
            self.track_file_modification(&tool_name, &args);

            let result = self
                .registry
                .execute(&tool_name, args, ctx)
                .await
                .unwrap_or_else(|e| format!("Error: {}", e));

            on_event(AgentEvent::Step(AgentStep {
                step_type: "tool_result".to_string(),
                tool: Some(tool_name),
                args: None,
                result: Some(result.clone()),
                content: None,
                timestamp: now_ms(),
            }));

            conversation.push(ChatMessage {
                role: "assistant".to_string(),
                content: response.content,
                tool_calls: None,
                tool_call_id: None,
            });
            conversation.push(ChatMessage {
                role: "user".to_string(),
                content: format!("Tool result:\n{}", result),
                tool_calls: None,
                tool_call_id: None,
            });
        } else {
            on_event(AgentEvent::Done(response.content.clone()));
            self.finalize_session(task, &response.content);
            return Ok(response.content);
        }
    }

    let msg = "[Agent reached max iterations]".to_string();
    on_event(AgentEvent::Done(msg.clone()));
    self.finalize_session(task, &msg);
    Ok(msg)
}

/// Auto-select between native and XML based on provider capabilities

        task: &str,
        ctx: &ToolContext,
        on_event: &(dyn Fn(AgentEvent) + Send + Sync),
    ) -> Result<String, CoreError> {
        if self.provider.capabilities().tool_calling {
            self.execute_native(task, ctx, on_event).await
        } else {
            self.execute_xml(task, ctx, on_event).await
        }
    }
}

/// Parse a tool call from content text when models output JSON instead of structured tool_calls

[fn parse_tool_call_from_content(content: &str, registry: &ToolRegistry) -> Option<ToolCall>]
fn parse_tool_call_from_content(content: &str, registry: &ToolRegistry) -> Option<ToolCall> {
    let trimmed = content.trim();

    // Try parsing as JSON object with "name" and "arguments" fields
    if let Ok(parsed) = serde_json::from_str::<serde_json::Value>(trimmed) {
        if let (Some(name), Some(args)) = (
            parsed.get("name").and_then(|n| n.as_str()),
            parsed.get("arguments"),
        ) {
            // Verify the tool exists in our registry
            if registry.get(name).is_some() {
                return Some(ToolCall {
                    id: format!("call_{}", uuid::Uuid::new_v4().to_string().replace("-", "")[..12].to_string()),
                    call_type: "function".to_string(),
                    function: ToolCallFunction {
                        name: name.to_string(),
                        arguments: serde_json::to_string(args).unwrap_or_default(),
                    },
                });
            }
        }
    }

    // Try extracting JSON from markdown code blocks
    if let Some(start) = trimmed.find("```json") {
        if let Some(end) = trimmed[start + 7..].find("```") {
            let json_str = trimmed[start + 7..start + 7 + end].trim();
            return parse_tool_call_from_content(json_str, registry);
        }
    }
    if let Some(start) = trimmed.find("```") {
        if let Some(end) = trimmed[start + 3..].find("```") {
            let json_str = trimmed[start + 3..start + 3 + end].trim();
            if json_str.starts_with('{') {
                return parse_tool_call_from_content(json_str, registry);
            }
        }
    }

    None
}

fn parse_xml_tool_call(text: &str) -> Option<(String, String)> {
    let tool_start = text.find("<tool>")?;
    let tool_end = text.find("</tool>")?;
    let tool_name = text[tool_start + 6..tool_end].trim().to_string();

    let args_start = text.find("<args>")?;
    let args_end = text.find("</args>")?;
    let args_str = text[args_start + 6..args_end].trim().to_string();

    Some((tool_name, args_str))
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_xml_tool_call_parsing() {
        let input = r#"<tool>read_file</tool><args>{"path":"test.txt"}</args>"#;
        let result = parse_xml_tool_call(input);
        assert!(result.is_some());
        let (name, args) = result.unwrap();
        assert_eq!(name, "read_file");
        assert_eq!(args, r#"{"path":"test.txt"}"#);

        // Also verify the args parse as valid JSON
        let parsed: serde_json::Value = serde_json::from_str(&args).unwrap();
        assert_eq!(parsed["path"], "test.txt");
    }

    #[test]
    fn test_xml_tool_call_with_whitespace() {
        let input = r#"
            <tool>  write_file  </tool>
            <args>  {"path": "src/main.rs", "content": "fn main() {}"}  </args>
        "#;
        let result = parse_xml_tool_call(input);
        assert!(result.is_some());
        let (name, args) = result.unwrap();

    assert_eq!(name, "write_file");
    // The args should be trimmed
    let parsed: serde_json::Value = serde_json::from_str(&args).unwrap();
    assert_eq!(parsed["path"], "src/main.rs");
}

#[test]

[fn test_xml_tool_call_missing_args()]
    fn test_xml_tool_call_missing_args() {
        // Only <tool> tag, no <args> — should return None
        let input = "<tool>read_file</tool>";
        let result = parse_xml_tool_call(input);
        assert!(result.is_none());
    }

[fn test_xml_tool_call_no_tags()]
    fn test_xml_tool_call_no_tags() {
        // Plain text with no XML tags
        let input = "I'll help you with that task.";
        let result = parse_xml_tool_call(input);
        assert!(result.is_none());
    }

use localcode_core::agent::{AgentEngine, AgentEvent, ToolRegistry, ToolContext};
use localcode_core::agent::builtin;
use localcode_core::llm::openai::OpenAIProvider;
use localcode_core::llm::anthropic::AnthropicProvider;
use localcode_core::llm::provider::LLMProvider;
use std::sync::Arc;
use serde::Deserialize;
use tauri::{AppHandle, Emitter};

use super::llm::LLMManager;

#[derive(Debug, Deserialize)]

[pub struct ChatHistoryEntry]
pub struct ChatHistoryEntry {
    pub role: String,
    pub content: String,
}

    task: String,
    project_path: String,
    current_file: String,
    current_file_content: String,
    chat_history: Option<Vec<ChatHistoryEntry>>,
    provider_name: Option<String>,
    app: AppHandle,
    state: tauri::State<'_, LLMManager>,
) -> Result<(), String> {
    let provider: Arc<dyn LLMProvider> = {
        let llm = state.lock().map_err(|e| e.to_string())?;
        let name = provider_name
            .as_deref()
            .unwrap_or(&llm.config.default_provider);

        match name {
            "openai" => {
                let key = llm.config.get_openai_key();
                let model = llm.config.get_openai_model();
                Arc::new(OpenAIProvider::new(&key, &model))
            }
            "anthropic" => {
                let key = llm.config.get_anthropic_key();
                let model = llm.config.get_anthropic_model();
                Arc::new(AnthropicProvider::new(&key, &model))
            }
            "ollama" | "local" => {
                let server_url = &llm.config.providers.local.server_url;
                let base_url = format!("{}/v1", server_url);
                let model = llm.config.providers.local.active_catalog_model
                    .clone()
                    .unwrap_or_else(|| "qwen2.5-coder:14b".to_string());
                Arc::new(OpenAIProvider::with_base_url("ollama", &base_url, &model))
            }
            _ => llm.local.clone() as Arc<dyn LLMProvider>,
        }
    };

    // Default to home directory if no project is open
    let project_path = if project_path.is_empty() {
        std::env::var("HOME").unwrap_or_else(|_| "/tmp".to_string())
    } else {
        project_path
    };

    let mut registry = ToolRegistry::new();
    builtin::register_all(&mut registry);

    let mut engine = AgentEngine::new(provider.clone(), registry);

    // Initialize memory, auto-discovery, and session
    engine.initialize(&project_path);

    // Add current file context to system prompt if available
    if !current_file_content.is_empty() {
        let file_ctx = format!(
            "\n\nCurrent file ({}):\n```\n{}\n```",
            current_file,
            current_file_content.chars().take(4000).collect::<String>()
        );
        engine = engine.with_system_prompt(format!(
            "You are LocalCode Agent, an autonomous AI coding assistant.{}",
            file_ctx
        ));
        // Re-initialize to merge memory context
        engine.initialize(&project_path);
    }

    // Build task with conversation history for memory
    let full_task = if let Some(ref history) = chat_history {
        if history.is_empty() {
            task
        } else {
            let mut context = String::from("## Conversation History\nHere is what was discussed previously in this session:\n\n");
            // Include last 10 messages max to avoid token overflow
            let start = if history.len() > 10 { history.len() - 10 } else { 0 };
            for entry in &history[start..] {
                let role_label = if entry.role == "user" { "User" } else { "Assistant" };
                context.push_str(&format!("**{}**: {}\n\n", role_label, entry.content));
            }
            context.push_str(&format!("## Current Task\n{}", task));

            context
        }
    } else {
        task
    };

    let ctx = ToolContext {
        project_path,
        current_file: if current_file.is_empty() {
            None
        } else {
            Some(current_file)
        },
        provider: Some(provider.clone()),
    };

    let app_clone = app.clone();
    let rid = response_id.clone();

    let result = engine
        .execute(&full_task, &ctx, &move |event| match event {
            AgentEvent::Step(step) => {
                let _ = app_clone.emit(
                    "agent-step",
                    serde_json::json!({"id": rid, "step": step}),
                );
            }
            AgentEvent::TextChunk(text) | AgentEvent::Done(text) => {
                let _ = app_clone.emit(
                    "llm-chat-chunk",
                    serde_json::json!({"id": rid, "chunk": text}),
                );
            }
            AgentEvent::Error(e) => {
                let _ = app_clone.emit(
                    "llm-chat-chunk",
                    serde_json::json!({"id": rid, "chunk": format!("\n\nError: {}", e)}),
                );
            }
        })
        .await;

    if let Err(e) = result {
        let _ = app.emit(
            "llm-chat-chunk",
            serde_json::json!({"id": response_id, "chunk": format!("\n\nError: {}", e)}),
        );
    }

    let _ = app.emit("llm-chat-done", serde_json::json!({"id": response_id}));
    Ok(())
}

#[tauri::command]

    project_path: String,
    app: AppHandle,
    state: tauri::State<'_, LLMManager>,
) -> Result<(), String> {
    let provider: Arc<dyn LLMProvider> = {
        let llm = state.lock().map_err(|e| e.to_string())?;
        let name = &llm.config.default_provider;

        match name.as_str() {
            "openai" => {
                let key = llm.config.get_openai_key();
                let model = llm.config.get_openai_model();
                Arc::new(OpenAIProvider::new(&key, &model))
            }
            "anthropic" => {
                let key = llm.config.get_anthropic_key();
                let model = llm.config.get_anthropic_model();
                Arc::new(AnthropicProvider::new(&key, &model))
            }
            "ollama" | "local" => {
                let server_url = &llm.config.providers.local.server_url;
                let base_url = format!("{}/v1", server_url);
                let model = llm.config.providers.local.active_catalog_model
                    .clone()
                    .unwrap_or_else(|| "qwen2.5-coder:14b".to_string());
                Arc::new(OpenAIProvider::with_base_url("ollama", &base_url, &model))
            }
            _ => llm.local.clone() as Arc<dyn LLMProvider>,
        }
    };

    let project_path = if project_path.is_empty() {
        std::env::var("HOME").unwrap_or_else(|_| "/tmp".to_string())
    } else {
        project_path
    };

    let mut registry = ToolRegistry::new();
    builtin::register_all(&mut registry);

    let mut engine = AgentEngine::new(provider.clone(), registry);
    engine.initialize(&project_path);

    // System prompt for composer mode
    engine = engine.with_system_prompt(
        "You are LocalCode Composer, a multi-file code generation assistant. \
         When given a task, identify the files that need to be created or modified \
         and make the changes using your tools (write_file, edit_file, create_file). \
         Work through each file methodically. After each file change, the UI will \
         show the diff to the user for review.".to_string()
    );
    engine.initialize(&project_path);

    let ctx = ToolContext {
        project_path,
        current_file: None,
        provider: Some(provider),
    };

    let app_clone = app.clone();

    let result = engine
        .execute(&task, &ctx, &move |event| match event {
            AgentEvent::Step(step) => {
                // Emit file changes for the composer UI
                let step_json = serde_json::to_value(&step).unwrap_or_default();
                let tool = step_json.get("tool").and_then(|v| v.as_str()).unwrap_or("");
                let result_str = step_json.get("result").and_then(|v| v.as_str()).unwrap_or("");

                if (tool == "write_file" || tool == "edit_file" || tool == "create_file")
                    && !result_str.starts_with("Error")
                {
                    let _ = app_clone.emit("composer-file-change", &step_json);
                }

                let _ = app_clone.emit("composer-step", &step_json);
            }
            AgentEvent::TextChunk(text) => {
                let _ = app_clone.emit(
                    "composer-text",
                    serde_json::json!({"chunk": text}),

                );
            }
            AgentEvent::Done(_text) => {
                let _ = app_clone.emit("composer-done", serde_json::json!({}));
            }
            AgentEvent::Error(e) => {
                let _ = app_clone.emit(
                    "composer-error",
                    serde_json::json!({"error": e}),
                );
            }
        })
        .await;

    if let Err(e) = result {
        let _ = app.emit(
            "composer-error",
            serde_json::json!({"error": e.to_string()}),
        );
    }

    let _ = app.emit("composer-done", serde_json::json!({}));
    Ok(())
}
